                            <span className="analytics-post-stats">
                                {post.views} views &middot; {post.reactions} reactions &middot; {post.comments} comments
                            </span>
                        </div>
                        <span className="analytics-post-score">{post.score}</span>
                    </motion.div>
                ))}
            </div>
        </div>
    );
};

export default TopPosts;

